external_knowledge:
- 'Popular documents' are those with more than 10 successful operation records;
- 'Actively engaged' implies performing operations on the documents;
- 'More than a dozen times' indicates the number of times is greater than 10;
- 'Under the 'Tenant1' domain' refers to documents associated with the Azure Active Directory tenant 'Tenant1'.

sql:
SELECT COUNT(*) as documents_accessed
FROM document_access_logs
WHERE user_id = '0';

SELECT platform_name, platform_version 
FROM platforms 
WHERE platform_id = '0';

SELECT documents.document_name, users.user_name
FROM documents
INNER JOIN users ON documents.protection_owner = users.user_id;

SELECT COUNT(*)
FROM activity_logs
WHERE operation = 'AcquireLicense';

SELECT *
FROM documents
WHERE protection_type = 'Simulated' AND protection_status = 'Applied';

SELECT document_name
FROM documents
WHERE protection_policy = 'Internal' AND protection_label = 'Internal';
